import { writable } from 'svelte/store';
import gameInstance from '@sudoku/game';

function createGameStore() {
    // 将 Game 实例放入可写 store
    const { subscribe, set } = writable(gameInstance);

    return {
        subscribe,
        
        // 重新初始化游戏
        init: (difficulty) => {
            gameInstance.startNew(difficulty);
            set(gameInstance); // 必须手动调用 set 来触发 UI 更新
        },

        // 填数操作
        guess: (row, col, value) => {
            gameInstance.makeMove(row, col, value);
            set(gameInstance); // 核心：修改后立即通知 Svelte
        },

        // 撤销操作
        undo: () => {
            gameInstance.undo();
            set(gameInstance);
        },

        // 暂停/恢复
        pause: () => {
            gameInstance.pause();
            set(gameInstance);
        },
        resume: () => {
            gameInstance.resume();
            set(gameInstance);
        }
    };
}

export const gameStore = createGameStore();
